previewCss:
.darma-loader-darma-custom-222 {
  color: var(--loader-color, #0891b2);
  width: calc(72px / cos(45deg));
  height: 14px;
  background: repeating-linear-gradient(-45deg,currentColor 0 15px,#0000 0 20px) left/200% 100%;
  animation: darma-loader-darma-custom-222-l3 2s infinite linear;
}
@keyframes darma-loader-darma-custom-222-l3 {
    100% {background-position:right}
}

